// CRÍTICO: Retorna ARRAY DIRETO (não objeto encapsulado)
// Compatibilidade com extensão Chrome VHSYS

const allRecords = $input.all();
const actions = allRecords.map(item => item.json);

// Log estruturado
const logEntry = {
  timestamp: new Date().toISOString(),
  route: 'get_update_extension_service_data',
  method: 'GET',
  total_actions: actions.length,
  success: true
};

console.log('[VHSYS] get_status:', JSON.stringify(logEntry));

// IMPORTANTE: Retornar como array no body
return {
  statusCode: 201,
  body: actions
};
